resource "aws_iam_role" "synthetic_role_026" {
  name = "synthetic_role_026"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "synthetic_role_026_policy" {
  name   = "synthetic_role_026-policy"
  role   = aws_iam_role.synthetic_role_026.id
  policy = jsonencode({
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "dynamodb:Scan",
                "dynamodb:Query"
            ],
            "Resource": "arn:aws:lambda:*:*:*"
        }
    ]
})
}
